#!/usr/bin/env python3
# advance_ring.py — evaluate gate and advance to next ring
import sys, time
from prometheus_api_client import PrometheusConnect

prom = PrometheusConnect(url="http://prometheus:9090")

RINGS = ["ring0", "ring1", "ring2", "ring3"]

def get_ring_metrics(ring: str, version: str) -> dict:
    def q(query):
        result = prom.custom_query(query.format(ring=ring, version=version))
        return float(result[0]["value"][1]) if result else None

    return {
        "p99_latency":   q('histogram_quantile(0.99, rate(claude_latency_seconds_bucket{{ring="{ring}",version="{version}"}}[10m]))'),
        "baseline_p99":  q('histogram_quantile(0.99, rate(claude_latency_seconds_bucket{{ring="{ring}",version="stable"}}[10m]))'),
        "error_rate":    q('rate(claude_errors_total{{ring="{ring}",version="{version}"}}[10m]) / rate(claude_requests_total{{ring="{ring}",version="{version}"}}[10m])'),
        "sample_count":  q('increase(claude_requests_total{{ring="{ring}",version="{version}"}}[{soak}h])'),
    }

def check_gate(ring_id: str, version: str, gate: dict) -> tuple[bool, str]:
    metrics = get_ring_metrics(ring_id, version)
    if metrics["sample_count"] is None or metrics["sample_count"] < gate["min_sample_requests"]:
        return False, f"Insufficient samples: {metrics['sample_count']:.0f} < {gate['min_sample_requests']}"
    if metrics["p99_latency"] and metrics["baseline_p99"]:
        delta_pct = (metrics["p99_latency"] - metrics["baseline_p99"]) / metrics["baseline_p99"] * 100
        if delta_pct > gate["p99_latency_delta_pct"]:
            return False, f"P99 latency +{delta_pct:.1f}% (limit {gate['p99_latency_delta_pct']}%)"
    if metrics["error_rate"] and metrics["error_rate"] > gate["error_rate_max"]:
        return False, f"Error rate {metrics['error_rate']:.4f} > {gate['error_rate_max']}"
    return True, "Gate passed"

def advance_ring(current_ring: str, version: str, gate: dict):
    passed, reason = check_gate(current_ring, version, gate)
    if not passed:
        print(f"[HOLD] {current_ring}: {reason}")
        sys.exit(1)
    idx = RINGS.index(current_ring)
    if idx + 1 >= len(RINGS):
        print(f"[COMPLETE] All rings deployed for {version}")
        sys.exit(0)
    next_ring = RINGS[idx + 1]
    print(f"[ADVANCE] {current_ring} -> {next_ring}: {reason}")
    update_ring_config(next_ring, version)  # write to ring-config CR via kubectl

if __name__ == "__main__":
    advance_ring(sys.argv[1], sys.argv[2], load_gate_config(sys.argv[1]))

#!/bin/bash
# bluegreen_ops.sh — promotion and rollback helpers

ROLLOUT="claude-gateway"
NAMESPACE="claude-api"

promote() {
  echo "Promoting green to active..."
  kubectl argo rollouts promote "$ROLLOUT" -n "$NAMESPACE"
  kubectl argo rollouts status "$ROLLOUT" -n "$NAMESPACE" --timeout 300s
  echo "Promotion complete. Monitor for 10 minutes before scaling down blue."
}

rollback() {
  echo "Aborting rollout — reverting to blue (active)..."
  kubectl argo rollouts abort "$ROLLOUT" -n "$NAMESPACE"
  # Argo Rollouts automatically redirects activeService back to the previous ReplicaSet
  kubectl argo rollouts status "$ROLLOUT" -n "$NAMESPACE" --timeout 120s
  echo "Rollback complete. Traffic on blue (previous version)."
}

watch_metrics() {
  watch -n 5 "kubectl argo rollouts get rollout $ROLLOUT -n $NAMESPACE"
}

case "$1" in
  promote) promote ;;
  rollback) rollback ;;
  watch) watch_metrics ;;
  *) echo "Usage: $0 {promote|rollback|watch}" ;;
esac
